                    WHERE Id = @Id AND Rol = 'Profesor'";

        var row = await connection.QuerySingleOrDefaultAsync(
            new CommandDefinition(sql, new { Id = id }, cancellationToken: cancellationToken)
        );

        if (row is null)
            return null;

        return Profesor.Reconstruir(
            (Guid)row.Id,
            (string)row.Pais,
            (string)row.Ciudad,
            (string)row.Calle,
            (int)row.Altura,
            (string)row.Email,
            (string)row.Contraseña,
            (string)row.Dni,
            (string)row.Nombre,
            (string)row.Apellido,
            (DateTime)row.FechaRegistro,
            (string)row.Especialidad
        );
    }

    public async Task<IEnumerable<Profesor>> ObtenerTodosAsync()
    {
        using var connection = _connectionFactory.CreateConnection();
        var sql = @"SELECT Id, Nombre, Apellido, Email, Contraseña, Dni,
                           Pais, Ciudad, Calle, Altura, FechaRegistro, Especialidad
                    FROM Usuarios
                    WHERE Rol = 'Profesor'";

        var rows = await connection.QueryAsync(sql);

        return rows.Select(row => Profesor.Reconstruir(
            (Guid)row.Id,
            (string)row.Pais,
            (string)row.Ciudad,
            (string)row.Calle,
            (int)row.Altura,
            (string)row.Email,
            (string)row.Contraseña,
            (string)row.Dni,
            (string)row.Nombre,
            (string)row.Apellido,
            (DateTime)row.FechaRegistro,
            (string)row.Especialidad
        ));
    }
}
